#include <bits/stdc++.h>
using namespace std;
int n , m , a[ 3000005 ] , b[ 3000005 ] , st[ 20 ][ 3000005 ] , lg[ 3000005 ] , sum = 1 ;
void init_st() {
	for( int i = 1 ; i <= 3 * n ; i++ )
	    st[ 0 ][ i ] = a[ i ];
	lg[ 1 ] = 0;
	for( int i = 2 ; i <= 3 * n ; i++ )
	    lg[ i ] = lg[ i / 2 ] + 1;
	for( int k = 1 ; k <= lg[ 3 * n ] ; k++ ) {
		for( int j = 1 ; j <= 3 * n ; j++ ) {
			st[ k ][ j ] = max( st[ k - 1 ][ j ] , st[ k - 1 ][ j + ( 1 << ( k - 1 ) ) ] );
		}
	}
}
int rmq_st( int l , int r ) {
	int k = lg[r - l + 1 ];
	return max(st[ k ][ r - ( 1 << k ) + 1 ] , st[ k ][ l ]);
}
void work( int x ) {
	int l = 1 , r = n - 1 , len = -1;
	while( l <= r ) {
		int mid = ( l + r ) / 2;
		if( rmq_st( x + n + 1 , x + mid + n ) >= b[ x ] || rmq_st( x + n - mid , x + n - 1 ) >= b[ x ] ){
			len = mid;
			r = mid - 1;
		}
		else
		    l = mid + 1 ;
	}
	cout << len << " ";
	return;
}
int main() {
	cin >> n;
	for( int i = 1 ; i <= n ; i++ )
	    cin >> a[ i ];
	for( int i = 1 ; i <= n ; i++ )
	    cin >> b[ i ];
	for( int i = 1 ; i <= n ; i++ ) {
		a[ i + n ] = a[ i + 2 * n ] = a[ i ];
		b[ i + n ] = b[ i + 2 * n ] = b[ i ];
	}
	init_st();
	for( int i = 1 ; i <= n ; i++ )
	    work( i );
    return 0;
}
